  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h);
};

const makeRemoteJid = (patientName) => {
  const eightDigits = String(hashName(patientName) % 100000000).padStart(8, '0');
  return `55119${eightDigits}@s.whatsapp.net`;
};

// DD/MM/AAAA HH:MM вҶ’ unix seconds (UTC, evita drift de timezone)
const toUnixSeconds = (dd, mm, yyyy, hh, mi) => {
  return Math.floor(Date.UTC(
    parseInt(yyyy, 10),
    parseInt(mm, 10) - 1,
    parseInt(dd, 10),
    parseInt(hh, 10),
    parseInt(mi, 10)
  ) / 1000);
};

const isAtendente = (name) => name.trim().toLowerCase() === 'atendente';

const messages = [];
const stats = { blocks_seen: blocks.length, blocks_kept: 0, blocks_dropped: 0, lines_dropped: 0 };

for (const block of blocks) {
  const lines = block.split('\n').map((l) => l.replace(/\r$/, '').trim()).filter((l) => l.length > 0);

  // Coleta sГі linhas que batem com o formato
  const matched = [];
  for (const line of lines) {
    const m = MSG_RE.exec(line);
    if (m) {
      matched.push(m);
    } else {
      stats.lines_dropped++;
    }
  }

  // Match-or-discard por bloco: precisa >=4 linhas vГЎlidas
  if (matched.length < 4) {
    stats.blocks_dropped++;
    if (matched.length > 0) {
      console.log(`Block dropped: only ${matched.length} valid lines (min 4)`);
    }
    continue;
  }

  // Identifica patientName do bloco вҖ” primeiro emissor nГЈo-atendente
  let patientName = null;
  for (const m of matched) {
    const sender = m[6].trim();
    if (!isAtendente(sender)) {
      patientName = sender;
      break;
    }
  }
  if (!patientName) {
    stats.blocks_dropped++;
    console.log('Block dropped: no patient sender found (only Atendente?)');
    continue;
  }

  const remoteJid = makeRemoteJid(patientName);
  stats.blocks_kept++;

  for (const m of matched) {
    const [, dd, mm, yyyy, hh, mi, sender, body] = m;
    const fromMe = isAtendente(sender);
    const ts = toUnixSeconds(dd, mm, yyyy, hh, mi);

    messages.push({
      remoteJid,
      fromMe,
      pushName: fromMe ? null : sender.trim(),
      body: body.trim(),
      messageType: 'conversation',
      timestamp: ts
    });
  }
}

if (messages.length === 0) {
  throw new Error(`No valid messages parsed. Stats: ${JSON.stringify(stats)}. Raw (first 500): ${rawText.slice(0, 500)}`);
}

// =====================================================================
// Validator estrito (safety net вҖ” conversor produz shape correto)
// =====================================================================
for (let i = 0; i < messages.length; i++) {
  const msg = messages[i];
  if (typeof msg.remoteJid !== 'string' || !msg.remoteJid.endsWith('@s.whatsapp.net')) {
    throw new Error(`Message #${i} bad remoteJid: ${JSON.stringify(msg)}`);
  }
  if (typeof msg.fromMe !== 'boolean') {
    throw new Error(`Message #${i} bad fromMe: ${JSON.stringify(msg)}`);
  }
  if (msg.fromMe ? msg.pushName !== null : typeof msg.pushName !== 'string') {
    throw new Error(`Message #${i} bad pushName for fromMe=${msg.fromMe}: ${JSON.stringify(msg)}`);
  }
  if (typeof msg.body !== 'string' || msg.body.length === 0) {
    throw new Error(`Message #${i} bad body: ${JSON.stringify(msg)}`);
  }
  if (msg.messageType !== 'conversation') {
    throw new Error(`Message #${i} bad messageType: ${JSON.stringify(msg)}`);
  }
  if (!Number.isInteger(msg.timestamp) || msg.timestamp < 1700000000 || msg.timestamp > 1800000000) {
    throw new Error(`Message #${i} bad timestamp: ${JSON.stringify(msg)}`);
  }
}

console.log(`Parse stats: ${JSON.stringify(stats)} вҶ’ ${messages.length} msgs`);

// SQL-escape pra Postgres node
const sqlEscape = (s) => String(s).replace(/'/g, "''");

const profileJson  = JSON.stringify(meta.profile);
const messagesJson = JSON.stringify(messages);

return [{
  json: {
    slug: meta.slug,
    label: meta.label,
    description: meta.description,
    profile: meta.profile,
    target: meta.target,
    count: meta.count,
    outcome: meta.outcome,
    batch_count: messages.length,
    parse_stats: stats,
    usage: response.usage || null,
    sql: {
      slug:        sqlEscape(meta.slug),
      label:       sqlEscape(meta.label),
      description: meta.description == null ? null : sqlEscape(meta.description),
      profile:     sqlEscape(profileJson),
      messages:    sqlEscape(messagesJson),
      target:      meta.target,
      created_by:  sqlEscape('n8n-simulator-v3')
    }
  }
}];
